{
  "summary": "This paper proposes lightweight out-of-distribution (OOD) detection methods for conditional language models (CLMs) by leveraging embeddings from encoder-decoder Transformers. It introduces Relative Mahalanobis Distance (RMD) and a binary classifier on embeddings to detect OOD inputs, combining these scores with perplexity to enable selective generation of high-quality outputs under distribution shift. The approach is evaluated on summarization and translation tasks, showing improved OOD detection and quality prediction over baselines.",
  "strengths": [
    {
      "point": "Effective OOD detection using model embeddings",
      "evidence": "RMD and binary classifier OOD scores outperform perplexity and other baselines on summarization and translation tasks."
    },
    {
      "point": "Selective generation framework combining OOD scores with perplexity",
      "evidence": "Combining OOD scores with perplexity improves correlation with human quality ratings and BLEURT, enabling better abstention on low-quality or OOD inputs."
    },
    {
      "point": "Task-agnostic approach with potential generalizability",
      "evidence": "Method is designed to be applicable beyond summarization and translation, including decoder-only models, without requiring separate detection models."
    },
    {
      "point": "Interpretability via attribution of OOD scores to input sentences",
      "evidence": "Visualization techniques are provided to help understand why examples are detected as OOD."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison to prior embedding-based OOD detection methods",
      "evidence": "The paper lacks discussion or comparison to existing embedding-based OOD detection approaches in NLP or vision, weakening novelty claims."
    },
    {
      "point": "Lack of justification for Gaussian assumption and embedding averaging",
      "evidence": "No empirical evidence or ablations are provided to justify modeling embeddings as Gaussians or using simple averaging over other pooling strategies."
    },
    {
      "point": "Limited evaluation metrics and baselines for OOD detection",
      "evidence": "Standard OOD metrics like AUROC and FPR95 are missing; recent state-of-the-art OOD detection baselines such as energy-based models or ensembles are not included."
    },
    {
      "point": "Reproducibility concerns due to missing experimental details",
      "evidence": "Details on background dataset sampling, model architectures, training hyperparameters, and combination methods for OOD scores and perplexity are insufficient."
    },
    {
      "point": "Claims of generalizability and applicability to decoder-only models are speculative",
      "evidence": "No experiments or detailed discussions support adaptation to decoder-only architectures or other conditional generation tasks beyond summarization and translation."
    },
    {
      "point": "Unclear robustness to subtle distribution shifts or adversarial inputs",
      "evidence": "The method's limitations in detecting near-OOD or adversarial examples are not addressed."
    },
    {
      "point": "Interpretability method lacks methodological detail and validation",
      "evidence": "Attribution techniques are mentioned but not thoroughly described or quantitatively evaluated."
    },
    {
      "point": "Potential bias in quality evaluation metrics on OOD data",
      "evidence": "Reliability of BLEURT scores on OOD translation data is not validated, possibly affecting conclusions."
    },
    {
      "point": "Dataset OOD-ness not systematically quantified",
      "evidence": "Only the 'law' dataset is analyzed for OOD overlap; other datasets' OOD characteristics remain unclear."
    }
  ],
  "questions": [
    {
      "question": "How does the method compare quantitatively to existing embedding-based OOD detection approaches?",
      "motivation": "Clarifying novelty and relative performance is important to position the contribution within prior work."
    },
    {
      "question": "How sensitive are the results to the Gaussian assumption and choice of embedding pooling?",
      "motivation": "Understanding these design choices is critical for method robustness and potential improvements."
    },
    {
      "question": "Can the approach be effectively adapted to decoder-only models and other generation tasks?",
      "motivation": "Empirical validation is needed to support claims of generalizability beyond the evaluated tasks."
    },
    {
      "question": "What are the effects of adversarial or subtle distribution shifts on detection performance?",
      "motivation": "Robustness to challenging OOD scenarios is crucial for real-world deployment."
    },
    {
      "question": "How reliable are learned quality metrics like BLEURT on OOD data?",
      "motivation": "Ensuring evaluation metrics remain valid under distribution shift is necessary for trustworthy conclusions."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
